```
import java.util.HashMap;
import java.util.Map;
public class ShakespeareanActorPerformanceAnalyzer {

 private Map playCountMap = new HashMap<>();
 private Map characterCountMap = new HashMap<>();
 private Map criticalReceptionMap = new HashMap<>();

 public void analyzePerformance(String[] plays, String[] characters, double[] criticalReception) {
 for (int i = 0; i < plays.length; i++) {
 String play = plays[i];
 String character = characters[i];
 double reception = criticalReception[i];

 // Update play count
 if (playCountMap.containsKey(play)) {
 playCountMap.put(play, playCountMap.get(play) + 1);
 } else {
 playCountMap.put(play, 1);
 }

 // Update character count
 if (characterCountMap.containsKey(character)) {
 characterCountMap.put(character, characterCountMap.get(character) + 1);
 } else {
 characterCountMap.put(character, 1);
 }

 // Update critical reception
 if (criticalReceptionMap.containsKey(character)) {
 double currentReception = criticalReceptionMap.get(character);
 criticalReceptionMap.put(character, (currentReception + reception) / 2);
 } else {
 criticalReceptionMap.put(character, reception);
 }
 }
 }

 public int getPlayCount(String play) {
 return playCountMap.getOrDefault(play, 0);
 }

 public int getCharacterCount(String character) {
 return characterCountMap.getOrDefault(character, 0);
 }

 public double getCriticalReception(String character) {
 return criticalReceptionMap.getOrDefault(character, 0.0);
 }
}
```
