 override func viewDidLoad() {
 super.viewDidLoad()
 // Populate the array with some sample data
 sights = [
 Sight(name: "Colosseum", location: "Piazza del Colosseo, 1, 00184 Roma RM, Italy", rating: 4),
 Sight(name: "Trevi Fountain", location: "Piazza di Trevi, 00187 Roma RM, Italy", rating: 5),
 Sight(name: "Pantheon", location: "Piazza della Rotonda, 00186 Roma RM, Italy", rating: 4),
 Sight(name: "Vatican Museums", location: "Viale Vaticano, 00165 Roma RM, Italy", rating: 5)
 ]
 // Set up the table view
 tableView.register(UITableViewCell.self, forCellReuseIdentifier: "cell")
 tableView.delegate = self
 tableView.dataSource = self
 // Add a segmented control to allow the user to sort the data
 let sortControl = UISegmentedControl(items: ["Name", "Location", "Rating"])
 sortControl.addTarget(self, action: #selector(sortSights), for: .valueChanged)
 navigationItem.titleView = sortControl
 }
 // Sort the sights array based on the selected segment
 @objc func sortSights(sender: UISegmentedControl) {
 switch sender.selectedSegmentIndex {
 case 0:
 sights.sort { $0.name < $1.name }
 case 1:
 sights.sort { $0.location < $1.location }
 case 2:
 sights.sort { $0.rating > $1.rating }
 default:
 break
 }
 tableView.reloadData()
 }
 // MARK: - Table view data source
 override func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
 return sights.count
 }
 override func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
 let cell = tableView.dequeueReusableCell(withIdentifier: "cell", for: indexPath)
