 String name = (String) employee.get("name");
 int age = Integer.parseInt(employee.get("age").toString());
 int salary = Integer.parseInt(employee.get("salary").toString());
 stmt.setInt(1, id);
 stmt.setString(2, name);
 stmt.setInt(3, age);
 stmt.setInt(4, salary);
 stmt.executeUpdate();
 }
 conn.close();
 } catch (Exception e) {
 e.printStackTrace();
 }
 }
}
