Here's an example of how to refactor the code using memoization:
```javascript
const fibonacci = (function() {
 const memo = {};
 function f(n) {
 let value;
 if (n in memo) {
 value = memo[n];
 } else {
 if (n < 2) {
 value = n;
 } else {
 value = f(n - 1) + f(n - 2);
 }
 memo[n] = value;
 }
 return value;
 }
 return f;
})();
