Consider the following function in Swift that takes in a string and returns an array of salient words:
func salience(text: String) -> [String] {
 var salientWords = [String]()

 let tagger = NSLinguisticTagger(tagSchemes: [.lemma], options: 0)
 tagger.string = text

 let range = NSRange(location: 0, length: text.utf16.count)
 let options: NSLinguisticTagger.Options = [.omitPunctuation, .omitWhitespace]

 tagger.enumerateTags(in: range, unit: .word, scheme: .lemma, options: options) { tag, tokenRange, _ in
 guard let lemma = tag?.rawValue else { return }
 let count = text.components(separatedBy: lemma).count - 1
 let tfidf = Double(count) * log(Double(text.count) / Double(count))
 if tfidf > 1.0 {
 salientWords.append(lemma)
 }
 }

 return salientWords
}
